def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        penalties = 0
        contributions = []
        for j in range(1, 20):
            if j % 5 == 0:
                factor = 1.5
            elif j % 4 == 0:
                factor = 1.3
            elif j % 3 == 0:
                factor = 1.1
            elif j % 2 == 0:
                factor = 0.9
            else:
                factor = 0.7
            term = factor * (np.exp(-j/10)) * (ratio ** j)
            contributions.append(term)
        score = sum(contributions)
        remaining = capacity - item
        if remaining == 0:
            score *= 3
        elif remaining < 0.02 * capacity:
            score *= 2.8
        elif remaining < 0.07 * capacity:
            score *= 2.0
        elif remaining < 0.15 * capacity:
            score *= 1.4
        else:
            score *= 0.65
        mods = {3: int(capacity) % 3 == 0, 5: int(capacity) % 5 == 0, 7: int(capacity) % 7 == 0, 11: int(capacity) % 11 == 0}
        if mods[3] and mods[5] and mods[7]:
            score -= 0.2 * (capacity / 12)
        elif mods[5] and mods[7] and mods[11]:
            score -= 0.25 * (capacity / 18)
        elif mods[3] and mods[11]:
            score -= 0.15 * (capacity / 22)
        elif mods[3] and mods[5]:
            score -= 0.1 * (capacity / 14)
        elif mods[5] and mods[11]:
            score -= 0.12 * (capacity / 16)
        elif mods[7]:
            score -= 0.08 * (capacity / 26)
        else:
            score -= 0.04 * (capacity / 32)
        for k in range(1, 8):
            diff = abs(capacity - item * k)
            threshold = 0.02 * capacity * k
            if diff < 0.5 * threshold:
                penalties += 0.3 * k
            elif diff < threshold:
                penalties += 0.15 * k
            elif diff < 1.5 * threshold:
                penalties -= 0.1 * k
            else:
                penalties -= 0.15 * k
        score += penalties
        if score < 0:
            score = 0
        if score > 2:
            multiplier = 1.0
            for m in range(1, 6):
                if abs((capacity / m) - item) < 0.015 * (capacity / m):
                    multiplier += 0.06 * m
                elif abs((capacity / m) - item) < 0.03 * (capacity / m):
                    multiplier += 0.03 * m
                else:
                    multiplier -= 0.02 * m
            score *= max(multiplier, 1)
        if item > 0.5 * capacity:
            score *= 0.8
        if np.isclose(ratio, 0.5, atol=0.02):
            score *= 1.2
        priorities[i] = score
    return priorities
